<section class="container section"><h1>Administrar reservaciones</h1><div class="table-wrap"><table><thead><tr><th>#</th><th>Cliente</th><th>Destino / Hotel</th><th>Fechas</th><th>Personas</th><th>Total</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php foreach($reservations as $r):?><tr><td><?=$r['id']?></td><td><?=Security::e($r['user_name'])?></td><td><?=Security::e(($r['destination_name']??'').' / '.($r['hotel_name']??'N/A'))?></td><td><?=$r['check_in']?> / <?=$r['check_out']?></td><td><?=$r['people']?></td><td>₡<?=number_format($r['total'],2)?></td><td><form class="inline" method="post" action="index.php?route=admin/reservation/status"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><input type="hidden" name="id" value="<?=$r['id']?>"><select name="status"><?php foreach(['pending'=>'Pendiente','confirmed'=>'Confirmada','cancelled'=>'Cancelada','completed'=>'Completada'] as $value=>$label):?><option value="<?=$value?>" <?=$r['status']===$value?'selected':''?>><?=$label?></option><?php endforeach;?></select><button class="btn small">Guardar</button></form></td><td><form class="inline" method="post" action="index.php?route=admin/reservation/delete" onsubmit="return confirm('¿Eliminar reservación?')"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><input type="hidden" name="id" value="<?=$r['id']?>"><button class="link danger">Eliminar</button></form></td></tr><?php endforeach;?></tbody></table></div></section>
